select USER_ID, USER_NAME, USER_PASS, ur.ROLE_ID, MOBILE_NO ,ur.ORG, ur.IS_AVAILABLE, INIT_PASS, ERROR_NUM, PASS_STATUS, LAST_PASS_UPDATE_TIME, RESERVED_FIELD4, ur.CREATE_BY, ur.CREATE_TIME, ur.UPDATE_TIME, ur.UPDATE_BY, ur.RESERVED_FIELD1, ur.RESERVED_FIELD2, ur.RESERVED_FIELD3, RESERVED_FIELD5, RESERVED_FIELD6, RESERVED_FIELD7, LAST_LOGIN_TIME, NOT_EXPIRED, ACCOUNT_NOT_LOCKED, CREDENTIALS_NOT_EXPIRED from TBL_USER ur left join TBL_ROLE ro on ur.ROLE_ID=ro.ROLE_ID where 1=1 AND (CAST(ro.WEIGHT AS bigint) < (SELECT CAST(re.WEIGHT AS bigint) FROM tbl_role re, tbl_user ur WHERE re.role_id = ur.role_id AND user_id=#{userReqParam.userId}))
and user_Name like '%${userReqParam.userName}%'
and ur.role_Id = #{userReqParam.roleId}
and ur.org = #{userReqParam.org}
and ur.IS_AVAILABLE = #{userReqParam.isAvailable}

